  const a = await fetchUser(1);   // 1 second
  const b = await fetchUser(2);   // 1 second
  return [a, b];
}

async function parallel() {
  // Both fire at the same time — total: ~1 second
  const [a, b] = await Promise.all([
    fetchUser(1),
    fetchUser(2)
  ]);
  return [a, b];
}

